{
  "primary_issue": "SQL injection vulnerability due to unsanitized user input concatenated directly into SQL query.",
  "evidence": "String sql = \"select * from t_user where xingming like '%\" + xingming + \"%'\";",
  "fix_summary": "Use a PreparedStatement with parameterized query instead of Statement to safely bind the user input. For example: String sql = \"select * from t_user where xingming like ?\"; then set the parameter with ps.setString(1, \"%\" + xingming + \"%\");"
}
